mapper.select:
/* wms-outbound-hanjinDlvryDb-sql-oracle.xml - selectCstOrdMtrV2Seq - 한진택배 접수SEQ 조회 */
SELECT MAX(COM_SEQ) AS SBMSEQ
  FROM CST_ORD_MTR_VW_V2
 WHERE COM_ORD_NUM = #{OBHDKEY}
   AND COM_WBL_NUM = #{WBLNO}
